    print("\n[3] Checking __init__ method...")
    try:
        tree = ast.parse(content)
        for node in ast.walk(tree):
            if isinstance(node, ast.ClassDef) and node.name == 'GradientNoiseInjector':
                methods = [n.name for n in node.body if isinstance(n, ast.FunctionDef)]
                if '__init__' in methods:
                    # Find __init__ method
                    for method in node.body:
                        if isinstance(method, ast.FunctionDef) and method.name == '__init__':
                            params = [arg.arg for arg in method.args.args]
                            defaults = [d for d in method.args.defaults]
                            if params == ['self', 'optimizer', 'eta', 'gamma']:
                                print(f"    ✓ __init__ method found with correct parameters: {params}")
                                if len(defaults) == 2:
                                    print(f"    ✓ __init__ has 2 default parameters")
                                else:
