                                return False
                else:
                    print(f"    ✗ __init__ method not found. Found methods: {methods}")
                    return False
    except Exception as e:
        print(f"    ✗ Error checking __init__: {e}")
        return False

    # Check 4: Verify step method exists
    print("\n[4] Checking step method...")
    try:
        tree = ast.parse(content)
        for node in ast.walk(tree):
            if isinstance(node, ast.ClassDef) and node.name == 'GradientNoiseInjector':
                methods = [n.name for n in node.body if isinstance(n, ast.FunctionDef)]
                if 'step' in methods:
                    print(f"    ✓ step method found")
                    # Check if it has closure parameter
                    for method in node.body:
                        if isinstance(method, ast.FunctionDef) and method.name == 'step':
                            params = [arg.arg for arg in method.args.args]
                            if params == ['self', 'closure']:
                                print(f"    ✓ step method has correct parameters: {params}")
