    else:
        print(f"    ✗ Missing step_count tracking")
        return False

    if 'sigma_sq = self.eta / (1 + self.step_count) ** self.gamma' in content:
        print(f"    ✓ Implements correct noise variance schedule")
    else:
        print(f"    ✗ Noise variance schedule not found or incorrect")
        return False

