    print("\n[7] Checking test file...")
    test_file = "/workspace/test/optim/test_gradient_noise.py"
    if not os.path.exists(test_file):
        print(f"    ✗ Test file not found: {test_file}")
        return False

    try:
        with open(test_file, 'r') as f:
            test_content = f.read()
        ast.parse(test_content)
        print(f"    ✓ Test file exists and has valid syntax")

        # Check for required test methods
        required_tests = [
            'test_noise_injection_occurs',
            'test_variance_decay_schedule',
            'test_wrapping_sgd_optimizer',
            'test_wrapping_adam_optimizer',
        ]

        all_found = True
        for test_name in required_tests:
            if test_name in test_content:
                print(f"    ✓ Found {test_name}")
            else:
                print(f"    ✗ Missing {test_name}")
                all_found = False

        if not all_found:
            return False

    except SyntaxError as e:
        print(f"    ✗ Test file syntax error: {e}")
        return False
    except Exception as e:
        print(f"    ✗ Error checking test file: {e}")
        return False

    # Check 8: Verify other methods exist
    print("\n[8] Checking other required methods...")
    required_methods = ['zero_grad', 'state_dict', 'load_state_dict', 'param_groups', '__getattr__']
    try:
        tree = ast.parse(content)
        for node in ast.walk(tree):
            if isinstance(node, ast.ClassDef) and node.name == 'GradientNoiseInjector':
                found_methods = set()
                for item in node.body:
                    if isinstance(item, ast.FunctionDef):
                        found_methods.add(item.name)
                    elif isinstance(item, ast.Attribute):
                        found_methods.add(item.attr)

                # Check function defs and properties
                method_names = {n.name for n in node.body if isinstance(n, ast.FunctionDef)}
                property_names = {n.name for n in node.body if isinstance(n, ast.FunctionDef) and
                                any(isinstance(dec, ast.Name) and dec.id == 'property'
                                    for dec in (n.decorator_list if hasattr(n, 'decorator_list') else []))}

                found_methods = method_names | property_names

                for method in required_methods:
                    if method in found_methods:
                        print(f"    ✓ Found {method}")
                    else:
                        print(f"    ✗ Missing {method}")
                        return False
    except Exception as e:
        print(f"    ✗ Error checking methods: {e}")
        return False

    print("\n" + "=" * 60)
    print("All verification checks passed! ✓")
    print("=" * 60)
    return True

if __name__ == "__main__":
    success = verify_implementation()
    sys.exit(0 if success else 1)

